import heapq
from collections import defaultdict
import math

def agent_step(state, history):
    def heuristic(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def a_star_search(start, goal, walls, blocks, known_obstacles, direction_weights, history, max_depth):
        def can_push_block(direction, from_pos, blocks, history):
            successes = sum(1 for turn in history if turn["action"].get("action") == direction and turn["moved"])
            failures = sum(1 for turn in history if turn["action"].get("action") == direction and not turn["moved"])
            return successes > failures  # Heuristic for push success

        effective_obstacles = blocks.union(known_obstacles)
        frontier = []
        heapq.heappush(frontier, (0, start))
        came_from = {}
        cost_so_far = {}
        came_from[start] = None
        cost_so_far[start] = 0

        while frontier:
            current_cost, current = heapq.heappop(frontier)

            if current == goal or len(reconstruct_path(came_from, start, current)) >= max_depth:
                break

            for dx, dy in [(-3, 0), (3, 0), (0, -3), (0, 3)]:  # Left, Right, Up, Down
                next_step = (current[0] + dx, current[1] + dy)
                if next_step in walls or next_step in effective_obstacles:
                    continue
                if next_step in blocks:
                    block_next = (next_step[0] + dx, next_step[1] + dy)
                    if block_next not in walls and block_next not in blocks and can_push_block(get_direction_key(dx, dy), current, blocks, history):
                        new_cost = cost_so_far[current] + (1 * direction_weights.get(get_direction_key(dx, dy), 1))
                        if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                            cost_so_far[next_step] = new_cost
                            priority = new_cost + heuristic(goal, next_step)
                            heapq.heappush(frontier, (priority, next_step))
                            came_from[next_step] = current
                    continue
                new_cost = cost_so_far[current] + (1 * direction_weights.get(get_direction_key(dx, dy), 1))
                if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                    cost_so_far[next_step] = new_cost
                    priority = new_cost + heuristic(goal, next_step)
                    heapq.heappush(frontier, (priority, next_step))
                    came_from[next_step] = current

        return reconstruct_path(came_from, start, goal)

    def reconstruct_path(came_from, start, goal):
        current = goal
        path = []
        while current != start and current in came_from:
            path.append(current)
            current = came_from.get(current)
        path.reverse()
        return path if path else None

    def get_direction_key(dx, dy):
        if dx == 3: return "MOVE_RIGHT"
        if dx == -3: return "MOVE_LEFT"
        if dy == 3: return "MOVE_DOWN"
        if dy == -3: return "MOVE_UP"
        return None

    def analyze_history(history):
        direction_success = defaultdict(int)
        direction_attempts = defaultdict(int)
        for turn in history:
            action = turn["action"].get("action")
            if action in ["MOVE_LEFT", "MOVE_RIGHT", "MOVE_UP", "MOVE_DOWN"]:
                direction_attempts[action] += 1
                if turn["moved"]:
                    direction_success[action] += 1
        direction_weights = {}
        for direction in ["MOVE_LEFT", "MOVE_RIGHT", "MOVE_UP", "MOVE_DOWN"]:
            if direction_attempts[direction] > 0:
                success_rate = direction_success[direction] / direction_attempts[direction]
                direction_weights[direction] = 1 / (success_rate + 0.01)  # Penalize low success
            else:
                direction_weights[direction] = 1
        return direction_weights

    def is_stuck(history):
        return len(history) >= 3 and not any(turn["moved"] for turn in history[-3:])

    player_pos = tuple(state["player"]["position"])
    goals = state["objects"]["goals"]
    walls = {tuple(wall["position"]) for wall in state["objects"]["walls"]}
    blocks = {tuple(block["position"]) for block in state["objects"]["blocks"]}

    # Update known obstacles with heuristic hints and history
    known_obstacles = set()
    for turn in history[-10:]:  # Recent history
        if not turn["moved"] and "action" in turn and turn["action"].get("action") in ["MOVE_LEFT", "MOVE_RIGHT", "MOVE_UP", "MOVE_DOWN"]:
            attempted_pos = list(turn["state"]["player"]["position"])
            direction = turn["action"]["action"]
            if direction == "MOVE_RIGHT": attempted_pos[0] += 3
            elif direction == "MOVE_LEFT": attempted_pos[0] -= 3
            elif direction == "MOVE_DOWN": attempted_pos[1] += 3
            elif direction == "MOVE_UP": attempted_pos[1] -= 3
            known_obstacles.add(tuple(attempted_pos))
    if state["movement"]["right_blocked"]: known_obstacles.add((player_pos[0] + 3, player_pos[1]))
    if state["movement"]["left_blocked"]: known_obstacles.add((player_pos[0] - 3, player_pos[1]))
    if state["movement"]["up_blocked"]: known_obstacles.add((player_pos[0], player_pos[1] - 3))
    if state["movement"]["down_blocked"]: known_obstacles.add((player_pos[0], player_pos[1] + 3))

    direction_weights = analyze_history(history)
    max_depth = min(state["resources"]["steps_remaining"], 20)

    if goals and state["level"]["current"] == 1:  # Level-specific strategy
        target_pos = [(3, 21), (0, 21)]  # From related knowledge
        for pos in target_pos:
            if heuristic(player_pos, pos) < 10:  # Near target
                path_to_pos = a_star_search(player_pos, pos, walls, blocks, known_obstacles, direction_weights, history, max_depth)
                if path_to_pos:
                    next_step = path_to_pos[0]
                    move_direction = get_direction_key(next_step[0] - player_pos[0], next_step[1] - player_pos[1])
                    return {"action": move_direction}
        # Probe walls as per strategy
        if player_pos == (3, 21) or player_pos == (0, 21):
            return {"action": "MOVE_DOWN"}  # Attempt to probe

    if goals:
        goal_pos = tuple(goals[0]["position"])
        path = a_star_search(player_pos, goal_pos, walls, blocks, known_obstacles, direction_weights, history, max_depth)
        if path:
            next_step = path[0]
            move_direction = get_direction_key(next_step[0] - player_pos[0], next_step[1] - player_pos[1])
            return {"action": move_direction}

    if is_stuck(history) or not path:
        selectables = state["objects"]["selectables"]
        if selectables and goals:
            goal_pos = tuple(goals[0]["position"])
            best_selectable = None
            best_score = float('inf')
            for selectable in selectables:
                sel_pos = tuple(selectable["position"])
                if sel_pos != player_pos:
                    sel_dist = heuristic(sel_pos, goal_pos)
                    past_success = sum(1 for turn in history if turn["action"].get("target_position") == list(sel_pos) and turn["moved"])
                    score = sel_dist - past_success  # Lower is better
                    if score < best_score:
                        best_score = score
                        best_selectable = selectable
            if best_selectable:
                return {"action": "CLICK", "target_position": best_selectable["position"]}

    possible_actions = ["MOVE_RIGHT", "MOVE_DOWN", "MOVE_LEFT", "MOVE_UP"]
    for action in sorted(possible_actions, key=lambda d: direction_weights.get(d, 1)):
        return {"action": action}  # Fallback to best weighted action
